ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?platformname ?university WHERE {
  ?platforms a :Platforms .
  ?platforms p:PlatformName ?platformname .
  ?platforms p:University ?university .
  ?platforms p:PlatformName ?platformname_o .
  ?platforms p:University ?university_o .
}
ORDER BY ASC(?platformname_o) ASC(?university_o) }
  component: { SELECT ?university WHERE {
  ?platforms a :Platforms .
  ?platforms p:University ?university .
  ?platforms p:University ?university_o .
}
ORDER BY ASC(?university_o) }
  component_2: { SELECT ?platformname WHERE {
  ?platforms a :Platforms .
  ?platforms p:PlatformName ?platformname .
  ?platforms p:PlatformName ?platformname_o .
}
ORDER BY ASC(?platformname_o) }
}

PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?u WHERE { ?x a :Platforms ; p:University ?u ; p:PlatformID ?id . BIND(xsd:integer(?id) AS ?i) FILTER(?i - 2*FLOOR(?i/2) = 1) } }
  component_2: { SELECT ?pn WHERE { ?x a :Platforms ; p:PlatformName ?pn ; p:PlatformID ?id . BIND(xsd:integer(?id) AS ?i) FILTER(?i - 2*FLOOR(?i/2) = 1) } }
  full: { SELECT ?pn ?u WHERE { ?x a :Platforms ; p:PlatformName ?pn ; p:University ?u ; p:PlatformID ?id . BIND(xsd:integer(?id) AS ?i) FILTER(?i - 2*FLOOR(?i/2) = 1) } }
}
